const items = $input.all();
const emails = [];

for (const item of items) {
  // Extract From
  let rawFrom = '';
  if (item.json.from && item.json.from.value) {
    const sender = item.json.from.value[0];
    rawFrom = sender.name ? `${sender.name} <${sender.address}>` : sender.address;
  }

  // Extract To
  let rawTo = '';
  if (item.json.to && item.json.to.value) {
    rawTo = item.json.to.value.map(v => v.address).join(', ');
  }

  const rawSubject = item.json.subject || '(No Subject)';

  // Parse sender name and email
  let senderName = '';
  let senderEmail = '';
  if (rawFrom.includes('<') && rawFrom.includes('>')) {
    const match = rawFrom.match(/<(.+?)>/);
    senderEmail = match ? match[1] : rawFrom;
    senderName = rawFrom.split('<')[0].trim();
  } else if (rawFrom.includes('@')) {
    senderEmail = rawFrom.trim();
    senderName = rawFrom.split('@')[0];
  } else {
    senderEmail = 'unknown@email.com';
    senderName = 'Unknown Sender';
  }

  const bodyText = item.json.text || '';
  const snippet = bodyText.substring(0, 200);

  // FIX: include 'from' field in fullContent for sender-based keyword matching
  const email = {
    messageId: item.json.id || '',
    threadId: item.json.threadId || item.json.id || '',
    from: rawFrom,
    senderEmail,
    senderName,
    to: rawTo,
    subject: rawSubject,
    bodyText,
    snippet,
    date: item.json.date || new Date().toISOString(),
    labels: item.json.labels || [],
    fullContent: `${rawSubject} ${bodyText} ${rawFrom}`.toLowerCase()
  };

  emails.push({ json: email });
}

return emails;

