for (const item of items) {
  const email = item.json;
  const content = email.fullContent || '';

  let category = '2';
  let priorityScore = 3;
  let reason = 'General or unclassified email';
  let matchedKeyword = '';
  let needsReply = false;

  // HIGH PRIORITY
  for (const keyword of HIGH_PRIORITY_KEYWORDS) {
    if (content.includes(keyword)) {
      category = '0';
      priorityScore = 9;
      matchedKeyword = keyword;
      reason = `High priority keyword: "${keyword}"`;
      needsReply = true;
      break;
    }
  }

  // MEDIUM PRIORITY
  if (category === '2') {
    for (const keyword of MEDIUM_PRIORITY_KEYWORDS) {
      if (content.includes(keyword)) {
        category = '1';
        priorityScore = 6;
        matchedKeyword = keyword;
        reason = `Medium priority keyword: "${keyword}"`;
        break;
      }
    }
  }

  // LOW PRIORITY
  if (category === '2') {
    for (const keyword of LOW_PRIORITY_KEYWORDS) {
      if (content.includes(keyword)) {
        priorityScore = 1;
        matchedKeyword = keyword;
        reason = `Low priority keyword: "${keyword}"`;
        break;
      }
    }
  }

  // LABEL STRATEGY
  let labelIdsToApply = [];
  let priorityLabel = '';

  if (category === '0') {
    priorityLabel = 'High Priority - Job / Work';
    labelIdsToApply = ['IMPORTANT', 'STARRED'];
  } else if (category === '1') {
    priorityLabel = 'Medium Priority - Learning';
    labelIdsToApply = ['IMPORTANT'];
  } else {
    priorityLabel = 'Low Priority - Promotions / Other';
    labelIdsToApply = [];
  }

  email.category = category;
  email.priorityScore = priorityScore;
  email.priorityLabel = priorityLabel;
  email.reason = reason;
  email.matchedKeyword = matchedKeyword;
  email.needsReply = needsReply;
  email.labelIdsToApply = labelIdsToApply;

  output.push({ json: email });
}

return output;

