// PARSE HIGH PRIORITY RESPONSE
// Reads Gemini output, strips any accidental markdown fences,
// parses JSON, and passes clean fields downstream.
// NOTE: Code in JavaScript3 + Merge2 nodes have been REMOVED.
//       senderEmail is already embedded in the AI prompt and
//       returned in the JSON response, so no merge is needed.
// ─────────────────────────────────────────────────────────────────

const items = $input.all();
const replies = [];

for (const item of items) {
  // Gemini node output structure: output[0].content[0].text
  const rawText = (
    item.json.output?.[0]?.content?.[0]?.text ||
    item.json.text ||
    item.json.output ||
    ''
  ).toString().trim();

  // Strip markdown fences if model returns them despite instructions
  const cleanText = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();

  let parsed = {};
  try {
    parsed = JSON.parse(cleanText);
  } catch (e) {
    // Fallback: best-effort plain text body
    parsed = {
      subject: `Re: ${item.json.subject || ''}`.trim(),
      body: cleanText || 'Thank you for your email. I will follow up shortly.',
      senderEmail: item.json.senderEmail || ''
    };
  }

  replies.push({
    json: {
      subject:     parsed.subject     || '(No Subject)',
      body:        parsed.body        || '',
      senderEmail: parsed.senderEmail || item.json.senderEmail || ''
    }
  });
}

return replies;

